var body = $json.body || $json;
var evalNotes = body.evaluationNotes || '';
var jobId = 'eval_' + Date.now() + '_' + Math.random().toString(36).substring(2, 6);

return [{
  json: {
    jobId: jobId,
    evaluationNotes: evalNotes,
    timestamp: new Date().toISOString()
  },
  binary: $binary
}];

var b = $binary || {};
var items = [];
for (var k of Object.keys(b)) {
  items.push({ json: { sourceField: k, fileName: b[k].fileName || k }, binary: { data: b[k] } });
}
if (items.length === 0) throw new Error('No files uploaded');
return items;

var items = $input.all();
var splitItems = $('Split Binary Files').all();
var reqText = '', propText = '';
for (var i = 0; i < items.length; i++) {
  var text = items[i].json.text || items[i].json.data || '';
  var sf = (splitItems[i] && splitItems[i].json.sourceField || '').toLowerCase();
  if (sf === 'requirements' || sf.indexOf('req') >= 0) {
    reqText += text + '\n\n';
  } else {
    propText += text + '\n\n';
  }
}
return [{ json: {
  requirementsText: reqText.trim(),
  proposalText: propText.trim(),
  totalCharacters: (reqText + propText).length
} }];

var mt = $('Merge Texts').first().json;
return [{ json: {
  requirementsText: mt.requirementsText || '',
  proposalText: mt.proposalText || ''
} }];

var reqs = $('Extract Requirements').first().json.requirements || $('Extract Requirements').first().json;
var propAnalysis = $json.proposalAnalysis || $json;
var mt = $('Merge Texts').first().json;

return [{ json: {
  requirements: reqs,
  proposalAnalysis: propAnalysis,
  proposalText: mt.proposalText || '',
  procurementInfo: {
    subject: (reqs.procurement_subject || propAnalysis.proposal_subject || 'Неизвестен'),
    authority: (reqs.contracting_authority || 'Неизвестен'),
    type: (reqs.procurement_type || 'неопределен')
  }
} }];

var data = $json;
var reqs = data.requirements || {};
var reqList = reqs.requirements || [];
var propAnalysis = data.proposalAnalysis || {};
var proposalText = data.proposalText || '';
var procInfo = data.procurementInfo || {};

if (reqList.length === 0) throw new Error('No requirements found in documentation');

// Init staticData for accumulation
var sd = $getWorkflowStaticData('global');
sd.findings = [];
sd.allRequirements = reqs;
sd.proposalAnalysis = propAnalysis;
sd.procurementInfo = procInfo;

var items = [];
for (var i = 0; i < reqList.length; i++) {
  items.push({
    json: {
      requirement: reqList[i],
      reqIndex: i,
      totalReqs: reqList.length,
      proposalAnalysis: propAnalysis,
      proposalText: proposalText
    }
  });
}
return items;

var sd = $getWorkflowStaticData('global');
var finding = $json.finding || $json;
sd.findings.push(finding);
return [{ json: { ok: true } }];

var sd = $getWorkflowStaticData('global');
var findings = sd.findings || [];
var reqs = sd.allRequirements || {};
var propAnalysis = sd.proposalAnalysis || {};
var procInfo = sd.procurementInfo || {};

// Count stats
var compliant = 0, partial = 0, nonCompliant = 0, missing = 0;
for (var i = 0; i < findings.length; i++) {
  var s = findings[i].status;
  if (s === 'COMPLIANT') compliant++;
  else if (s === 'PARTIALLY_COMPLIANT') partial++;
  else if (s === 'NON_COMPLIANT') nonCompliant++;
  else if (s === 'MISSING') missing++;
}

return [{ json: {
  findings: findings,
  requirements: reqs,
  proposalAnalysis: propAnalysis,
  procurementInfo: procInfo,
  stats: {
    total: findings.length,
    compliant: compliant,
    partiallyCompliant: partial,
    nonCompliant: nonCompliant,
    missing: missing
  }
} }];

var af = $('Assemble Findings').first().json;
var legalValidation = $json.legalValidation || $json;

return [{ json: {
  findings: af.findings,
  legalValidation: legalValidation,
  requirements: af.requirements,
  proposalAnalysis: af.proposalAnalysis,
  procurementInfo: af.procurementInfo,
  stats: af.stats
} }];

var sd = $getWorkflowStaticData('global');
var af = $('Assemble Findings').first().json;
var reportText = $json.reportText || $json.text || '';
var stats = af.stats || {};
var legalVal = $('After Legal Validation').first().json.legalValidation || {};
var overallRec = (legalVal.overall_conclusion || legalVal.overall_recommendation || {}).action || 'N/A';

// Clean up staticData
sd.findings = [];
sd.allRequirements = null;
sd.proposalAnalysis = null;
sd.procurementInfo = null;

var wc = reportText.trim().split(/\s+/).length;

return [{ json: {
  success: true,
  finalDocument: reportText,
  statusPayload: {
    jobId: $('Init Job').first().json.jobId,
    status: 'completed',
    phase: 'completed',
    progress: 100,
    message: 'Оценката е завършена!',
    result: {
      text: reportText,
      stats: {
        wordCount: wc,
        estimatedPages: Math.round(wc / 375),
        totalRequirements: stats.total || 0,
        compliant: stats.compliant || 0,
        partiallyCompliant: stats.partiallyCompliant || 0,
        nonCompliant: stats.nonCompliant || 0,
        missing: stats.missing || 0,
        overallRecommendation: overallRec,
        disqualificationGrounds: (legalVal.overall_conclusion || legalVal.overall_recommendation || {}).disqualification_grounds_count || 0
      }
    }
  }
} }];
